import heapq

def solve(grid: list[list[int]], k: int) -> int:
    m = len(grid)
    n = len(grid[0])
    # Precompute teleport_list
    teleport_list = [[[] for _ in range(n)] for _ in range(m)]
    for i in range(m):
        for j in range(n):
            val = grid[i][j]
            for x in range(m):
                for y in range(n):
                    if grid[x][y] <= val:
                        teleport_list[i][j].append((x, y))
    # Initialize DP
    INF = float('inf')
    dp = [[[INF] * (k + 1) for _ in range(n)] for _ in range(m)]
    dp[0][0][0] = 0
    # Priority queue
    heap = []
    heapq.heappush(heap, (0, 0, 0, 0))
    # Directions for regular moves: right and down
    while heap:
        cost, x, y, t = heapq.heappop(heap)
        # Check if we reached the destination
        if x == m - 1 and y == n - 1:
            return cost
        # If current cost is higher than the stored one, skip
        if cost > dp[x][y][t]:
            continue
        # Regular moves: right and down
        # Right
        if y + 1 < n:
            new_cost = cost + grid[x][y + 1]
            if new_cost < dp[x][y + 1][t]:
                dp[x][y + 1][t] = new_cost
                heapq.heappush(heap, (new_cost, x, y + 1, t))
        # Down
        if x + 1 < m:
            new_cost = cost + grid[x + 1][y]
            if new_cost < dp[x + 1][y][t]:
                dp[x + 1][y][t] = new_cost
                heapq.heappush(heap, (new_cost, x + 1, y, t))
        # Teleportation
        if t < k:
            for (nx, ny) in teleport_list[x][y]:
                new_t = t + 1
                if cost < dp[nx][ny][new_t]:
                    dp[nx][ny][new_t] = cost
                    heapq.heappush(heap, (cost, nx, ny, new_t))
    # If not found (should not happen)
    return dp[m - 1][n - 1][k]
